// "name" adlı dəyişən yaradıram
var name = "Aysel";
console.log(name); // nəticə: Aysel

// Dəyişənin içindəkini dəyişirəm
name = "Kamran";
console.log(name); // nəticə: Kamran

// Hoisting nümunəsi
console.log(toy); // nəticə: undefined (xəta vermir!)
var toy = "robot";
console.log(toy); // nəticə: robot

// Funksiya scope nümunəsi
function test() {
  var color = "blue";
  console.log(color); // nəticə: blue
}
test();
// console.log(color); // Xəta: color is not defined, çünki funksiya xaricində işləmir

// var ilə təkrar elan etmək olar
var gadget = "phone";
var gadget = "earphones";
console.log(gadget); // nəticə: earphones

// let ilə təkrar elan etmək olmaz
let drink = "cola";
// let drink = "water"; // Xəta: drink has already been declared

// const ilə dəyəri dəyişmək olmaz
const name = "Kamran";
// name = "Murad"; // Xəta: Assignment to constant variable

