content.code:
// Create a variable called "name"
var name = "Aysel";
console.log(name); // Output: Aysel

// Change the variable’s contents
name = "Kamran";
console.log(name); // Output: Kamran

// Hoisting example
console.log(toy); // Output: undefined (no error!)
var toy = "robot";
console.log(toy); // Output: robot

// Function scope example
function test() {
  var color = "blue";
  console.log(color); // Output: blue
}
test();
// console.log(color); // Error: color is not defined, because it doesn’t exist outside the function

// Redeclaring with var is allowed
var gadget = "phone";
var gadget = "earphones";
console.log(gadget); // Output: earphones

// Redeclaring with let is not allowed
let drink = "cola";
// let drink = "water"; // Error: drink has already been declared

// Changing value with const is not allowed
const name = "Kamran";
// name = "Murad"; // Error: Assignment to constant variable

