// Создаём переменную под названием "name"
var name = "Айсель";
console.log(name); // Вывод: Айсель

// Меняем содержимое переменной
name = "Кямран";
console.log(name); // Вывод: Кямран

// Пример hoisting
console.log(toy); // Вывод: undefined (без ошибки!)
var toy = "робот";
console.log(toy); // Вывод: робот

// Пример функциональной области видимости
function test() {
  var color = "синий";
  console.log(color); // Вывод: синий
}
test();
// console.log(color); // Ошибка: color не определён, так как не существует вне функции

// Повторное объявление с var разрешено
var gadget = "телефон";
var gadget = "наушники";
console.log(gadget); // Вывод: наушники

// Повторное объявление с let не разрешено
let drink = "кола";
// let drink = "вода"; // Ошибка: drink уже объявлена

// Изменение значения с const не разрешено
const name = "Кямран";
// name = "Мурад"; // Ошибка: Assignment to constant variable

